MERGE INTO CONSULTAS FIN USING (SELECT '800080ActividadesXVigencias' INFORME ,TO_CLOB(q'[SELECT TO_CHAR(VIGENCIA) AS VIGENCIA,CODIGOPROYECTO AS CODIGO_PROYECTO, COMPONENTE, ACTIVIDAD, CANTIDAD, COSTOUNITARIO AS COSTO_UNITARIO, DESCRIPCION FROM COMPONENTES_ACTIVIDADES 
WHERE COMPANIA = s$compania$s AND VIGENCIA = s$vigencia$s ORDER BY CODIGOPROYECTO, COMPONENTE, ACTIVIDAD]') CONSULTA, -1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);